import { Link } from "gatsby"
import React from 'react';
import { graphql } from 'gatsby';
import Img from "gatsby-image"
import Layout from '../components/layout';
import Download from '../components/download';
import Buy from '../components/buy';
import Slider from "react-slick";
import "slick-carousel/slick/slick.css";
import "slick-carousel/slick/slick-theme.css";

const sliderStyle = {
    /* overflow: hidden; */
    /* display: block; */
    margin: `9%`,
    marginTop:`0`,
    marginBottom: `10%`,
    border: `1px solid`
};


const PostTemplate = ({ data }) => {


const settings = {
        dots: true,
        infinite: true,
        speed: 500,
        slidesToShow: 1,
        slidesToScroll: 1

};

  const { markdownRemark } = data;
  const { frontmatter, html } = markdownRemark;
  return (
    <Layout>
      <section style={{margin:0.5+`em`,overflow:`hidden`}}>
        <ul className="breadcrumb">
        <li><Link to="/">Home</Link></li>
        <li><Link to="/books">Books</Link></li>
        <li>{frontmatter.title}</li>
        </ul>
        <h1 style={{textAlign:`center`}}>{frontmatter.title}</h1>
       <div style={{float:`left`,width:`15em`}}>
       <Slider style={sliderStyle} {...settings} >
        { frontmatter.preview1 && <div><Img fluid={frontmatter.preview1.childImageSharp.fluid} alt={frontmatter.title} /></div> }
        { frontmatter.preview2 && <div><Img fluid={frontmatter.preview2.childImageSharp.fluid} alt={frontmatter.title} /></div> }
        { frontmatter.preview3 && <div><Img fluid={frontmatter.preview3.childImageSharp.fluid} alt={frontmatter.title} /></div> }
      </Slider>
     { frontmatter.buy && <Buy style={{width:`82%`,margin:`0 9%`,display:`block`}} /> }
     { frontmatter.download && <Download style={{width:`82%`,margin:`0 9%`,display:`block`}} link={ frontmatter.download  } /> }
      </div>
      <div dangerouslySetInnerHTML={{ __html: html }} />
          <em>{frontmatter.date}</em>
      </section>
    </Layout>
  );
};

export default PostTemplate;



export const pageQuery = graphql`
  query($slug: String!) {
  	markdownRemark(fields: { slug: { eq: $slug } }) {
      html
      frontmatter {
        date(formatString: "MMMM DD, YYYY")
        title
        download
        buy
        preview1 {
            childImageSharp {
                fluid {
                    ...GatsbyImageSharpFluid
                }
            }
        }
        preview2 {
            childImageSharp {
                fluid {
                    ...GatsbyImageSharpFluid
                }
            }
        }
        preview3 {
            childImageSharp {
                fluid {
                    ...GatsbyImageSharpFluid
                }
            }

        }

      }
    }
}`;
